// FOR LOG SCALE
Math.sign =
    Math.sign ||
    function(x) {
        return (x > 0) - (x < 0) || +x;
    };

Math.log1p =
    Math.log1p ||
    function(x) {
        x = Number(x);
        if (x < -1 || x !== x) {
            return NaN;
        }
        if (x === 0 || x === Infinity) {
            return x;
        }

        var nearX = x + 1 - 1;

        return nearX === 0 ? x : x * (Math.log(x + 1) / nearX);
    };

Math.expm1 =
    Math.expm1 ||
    function(x) {
        return Math.exp(x) - 1;
    };
